import uuid
from datetime import datetime

class ClinicScheduler:
    def __init__(self, patients=None, providers=None, services=None, appointments=None):
        self.patients = {p['patient_id']: p for p in (patients or [])}
        self.providers = {p['provider_id']: p for p in (providers or [])}
        self.services = {s['service_id']: s for s in (services or [])}
        self.appointments = appointments or []

    def list_patient_appointments(self, patient_id: str) -> dict:
        """列出某位患者的所有预约"""
        results = [a for a in self.appointments if a.get('patient_id') == patient_id]
        return {'success': True, 'data': results}

    def list_provider_appointments(self, provider_id: str, date: str = None) -> dict:
        """列出某位医生的预约，可按日期过滤"""
        results = [a for a in self.appointments if a.get('provider_id') == provider_id]
        if date:
            results = [a for a in results if a.get('date') == date]
        return {'success': True, 'data': results}

    def get_patient_info(self, patient_id: str) -> dict:
        """获取患者信息"""
        p = self.patients.get(patient_id)
        if p:
            return {'success': True, 'data': p}
        return {'success': False, 'error': f'患者 {patient_id} 不存在'}

    def create_appointment(self, patient_id: str, provider_id: str, service_id: str, date: str, start_time: str, end_time: str) -> dict:
        """创建新预约"""
        if patient_id not in self.patients:
            return {'success': False, 'error': f'患者 {patient_id} 不存在'}
        if provider_id not in self.providers:
            return {'success': False, 'error': f'医生 {provider_id} 不存在'}
        # 检查时间冲突
        for a in self.appointments:
            if a['provider_id'] == provider_id and a['date'] == date:
                if not (end_time <= a['start_time'] or start_time >= a['end_time']):
                    return {'success': False, 'error': f'医生 {provider_id} 在 {date} {start_time}-{end_time} 有冲突'}
        appt = {
            'appointment_id': f'APPT-{uuid.uuid4().hex[:8].upper()}',
            'patient_id': patient_id,
            'provider_id': provider_id,
            'service_id': service_id,
            'date': date,
            'start_time': start_time,
            'end_time': end_time,
            'status': 'pending'
        }
        self.appointments.append(appt)
        return {'success': True, 'data': appt}

    def cancel_appointment(self, appointment_id: str) -> dict:
        """取消预约"""
        for a in self.appointments:
            if a['appointment_id'] == appointment_id:
                if a['status'] == 'cancelled':
                    return {'success': False, 'error': '该预约已取消'}
                a['status'] = 'cancelled'
                return {'success': True, 'data': a}
        return {'success': False, 'error': f'预约 {appointment_id} 不存在'}

    def list_services(self) -> dict:
        """列出所有可用服务"""
        return {'success': True, 'data': list(self.services.values())}

    def list_providers(self, service_id: str = None) -> dict:
        """列出所有医生，可按服务过滤"""
        results = list(self.providers.values())
        if service_id:
            results = [p for p in results if service_id in p.get('services', [])]
        return {'success': True, 'data': results}
